namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    public List<Notification> GetInitialNotifications()
    {
        lock (_lock)
        {
            var notifications = new List<Notification>();
            for (int i = 0; i < 5; i++)
            {
                notifications.Add(new Notification(
                    _nextId++,
                    $"Welcome notification #{_nextId - 1}",
                    DateTime.UtcNow.AddMinutes(-10 + i)));
            }
            return notifications;
        }
    }

    public List<Notification> CheckForNewNotifications()
    {
        lock (_lock)
        {
            // Simulate ~30% chance of a new notification on each poll
            if (Random.Shared.Next(0, 10) < 3)
            {
                return
                [
                    new Notification(
                        _nextId++,
                        $"New activity detected (#{_nextId - 1})",
                        DateTime.UtcNow)
                ];
            }
            return [];
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject BlazorNotifications.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @n.Message
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<BlazorNotifications.Services.Notification> notifications = new();
    private CancellationTokenSource? cts;

    protected override void OnInitialized()
    {
        // Runs during SSR and again on the interactive circuit.
        // Load initial data so it appears in the server-rendered HTML.
        notifications = NotificationService.GetInitialNotifications();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires on an interactive circuit, never during
            // static SSR, so the polling loop starts only when the page is live.
            cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), token).ConfigureAwait(false);

            var newItems = NotificationService.CheckForNewNotifications();
            if (newItems.Count > 0)
            {
                await InvokeAsync(() =>
                {
                    notifications.AddRange(newItems);
                    StateHasChanged();
                });
            }
        }
    }

    public void Dispose()
    {
        cts?.Cancel();
        cts?.Dispose();
    }
}

